function t1272_hideMenuOnMobile(link, rec) {
  if (!rec || !link || window.innerWidth > 960) return !1;
  var menu = rec.querySelector(".t-menu-base");
  var burger = rec.querySelector(".tmenu-mobile");
  if (link.matches('[href*="#"]')) {
    if (
      menu.classList.contains("t-menu-base_positionabsolute") ||
      (burger && !burger.classList.contains("tmenu-mobile_positionfixed"))
    ) {
      menu.style.display = "none";
      menu.style.opacity = "0";
    }
    t1272_closeMobileMenu(rec);
  }
}
function t1272_closeMobileMenu(rec, options) {
  var menu = rec.querySelector(".t-menu-base");
  var mobileMenu = rec.querySelector(".tmenu-mobile");
  var mobileBurger = mobileMenu
    ? mobileMenu.querySelector(".t-menuburger")
    : null;
  if (menu) {
    t_menuBase__FadeOut(menu, 300);
    menu.classList.remove("t-menu-base__burgermenu_opened");
  }
  if (mobileMenu) mobileMenu.classList.remove("tmenu-mobile_opened");
  if (mobileBurger) {
    mobileBurger.classList.remove("t-menuburger-opened", "t-menu-burger_open");
    mobileBurger.setAttribute("aria-expanded", "false");
  }
  document.body.classList.remove("t1272__body_menushowed");
  if (options && options.currentMode === "edit") {
    document.body.classList.remove("t-menu-base_opened");
  }
}
function t1272_centerElementInMenu(recId, selectors) {
  var rec = document.getElementById("rec" + recId);
  if (!rec) return;
  var container = rec.querySelector(selectors.containerSelector);
  if (!container) return;
  var centerBlock = container.querySelector(selectors.centerSelector);
  if (!centerBlock) return;
  var leftSideBlock = container.querySelector(selectors.leftSideSelector);
  if (!leftSideBlock) return;
  var centerWidth = centerBlock.offsetWidth || 0;
  if (centerWidth === 0) return;
  var gap = 50;
  var containerPadding =
    parseInt(getComputedStyle(container).paddingLeft, 10) || 0;
  var sideWidth =
    (container.offsetWidth - containerPadding * 2 - gap * 2 - centerWidth) / 2;
  leftSideBlock.style.flex = "1 1 " + sideWidth + "px";
  leftSideBlock.style.maxWidth = sideWidth + "px";
}
function t1272_handleLangWidget(rec) {
  var langDropdown = rec.querySelector(".t-menu-base__langs_dropdown");
  if (!langDropdown) return;
  var langButton = rec.querySelector(".js-lang-button");
  if (!langButton) return;
  var timer;
  function positionLangDropdown() {
    var dropdownRect = langDropdown.getBoundingClientRect();
    var viewportHeight = window.innerHeight;
    var spaceBelow = viewportHeight - dropdownRect.bottom;
    var spaceAbove = dropdownRect.top;
    if (spaceBelow < 0 && spaceAbove > Math.abs(spaceBelow)) {
      langDropdown.classList.add("t-menu-base__langs_dropdown_top");
    } else {
      langDropdown.classList.remove("t-menu-base__langs_dropdown_top");
    }
  }
  function showLangDropdown() {
    clearTimeout(timer);
    langDropdown.classList.add("t-menu-base__langs_dropdown_show");
    positionLangDropdown();
  }
  function hideLangDropdown() {
    timer = setTimeout(function () {
      langDropdown.classList.remove("t-menu-base__langs_dropdown_show");
    }, 300);
  }
  function recalcHorizontalCoord() {
    if (!langDropdown) return;
    var MOBILE_WIDTH = 960;
    var isMobile = window.innerWidth <= MOBILE_WIDTH;
    if (isMobile) return;
    var langDropdownRect = langDropdown.getBoundingClientRect();
    var windowWidth = window.innerWidth;
    if (langDropdownRect.right > windowWidth) {
      langDropdown.classList.add("t-menu-base__langs_dropdown_overflowed");
    } else {
      langDropdown.classList.remove("t-menu-base__langs_dropdown_overflowed");
    }
  }
  recalcHorizontalCoord();
  window.addEventListener("resize", t_throttle(recalcHorizontalCoord, 200));
  langButton.addEventListener("mouseenter", showLangDropdown);
  langButton.addEventListener("mouseleave", hideLangDropdown);
  langDropdown.addEventListener("mouseenter", showLangDropdown);
  langDropdown.addEventListener("mouseleave", hideLangDropdown);
}
function t1272_menuBase__createMobileMenu(recid, selector) {
  var rec = document.getElementById("rec" + recid);
  if (!rec) return;
  var menu = rec.querySelector(selector);
  var mobileMenu = rec.querySelector(".tmenu-mobile");
  if (!mobileMenu) return;
  var mobileMenuOpenClass = "tmenu-mobile_opened";
  var menuMobileBurgerhook = menu
    ? menu.getAttribute("data-mobile-burgerhook")
    : "";
  if (
    menu &&
    menu.classList.contains(selector.slice(1) + "__mobile_burgerhook") &&
    menuMobileBurgerhook
  ) {
    var mobileBurger =
      mobileMenu.querySelector(".tmenu-mobile__burger") ||
      mobileMenu.querySelector(".t-menuburger");
    if (mobileBurger) {
      var mobileBurgerParent = mobileBurger.parentElement;
      var link = document.createElement("a");
      link.href = menuMobileBurgerhook;
      if (mobileBurgerParent) {
        link.appendChild(mobileBurger);
        mobileBurgerParent.appendChild(link);
      }
    }
    return;
  }
  var currentMode = document
    .querySelector(".t-records")
    .getAttribute("data-tilda-mode");
  var mobileBurger = mobileMenu.querySelector(".t-menuburger");
  mobileMenu.addEventListener("click", function (event) {
    if (event.target.closest("a")) return;
    if (mobileMenu.classList.contains(mobileMenuOpenClass)) {
      t1272_closeMobileMenu(rec, { currentMode: currentMode });
    } else {
      t_menuBase__fadeIn(menu, 300, function () {
        if (menu.style.transform) menu.style.transform = "";
        if (menu.style.opacity) menu.style.opacity = "";
      });
      mobileMenu.classList.add(mobileMenuOpenClass);
      mobileBurger.classList.add("t-menuburger-opened", "t-menu-burger_open");
      if (!menu.classList.contains("t-menu-base__burgermenu__dropdown")) {
        document.body.classList.add("t1272__body_menushowed");
      }
      menu.classList.add("t-menu-base__burgermenu_opened");
      mobileBurger.setAttribute("aria-expanded", "true");
      if (menu.classList.contains("tmenu-mobile__menucontent_fixed")) {
        var burgerHeight = getComputedStyle(mobileMenu).height;
        var burgerBorderSize = getComputedStyle(mobileMenu).borderBottom || 0;
        menu.style.top = burgerHeight + burgerBorderSize;
      }
      if (currentMode === "edit") {
        document.body.classList.add("t-menu-base_opened");
      }
    }
    t1272_menuBase__checkOverflow(recid, selector);
  });
  if (window.innerWidth <= 960) {
    document.addEventListener("click", function (e) {
      if (
        !e.target.closest(
          '.t-menu-base__overlay, .t-menu-base__burgermenu__close-button, a[href*="#"]:not(.tooltipstered):not(.t794__tm-link):not(.t978__tm-link):not(.t966__tm-link):not(.t978__menu-link_hook):not(.t-menuwidgeticons__link_wishlist):not(.t-menuwidgeticons__link_cart)',
        )
      )
        return;
      var isSidebar = menu.classList.contains(
        "t-menu-base__burgermenu__sidebar",
      );
      if (!menu) return;
      if (
        !isSidebar &&
        !menu.classList.contains("tmenu-mobile__menucontent_fixed")
      )
        return;
      t1272_closeMobileMenu(rec);
    });
    rec.addEventListener("click", function (e) {
      if (!menu || !menu.classList.contains("tmenu-mobile__menucontent_fixed"))
        return;
      var menuLink = e.target.closest(
        ".t-menu__link-item, .t978__submenu-link, .t978__innermenu-link, .t966__menu-link, .t-menusub__link-item, .t-btn, .t794__link",
      );
      if (!menuLink) return;
      var submenuHooks = [
        "t978__menu-link_hook",
        "t978__tm-link",
        "t966__tm-link",
        "t794__tm-link",
      ];
      var isSubmenuHook = submenuHooks.some(function (cls) {
        return menuLink.classList.contains(cls);
      });
      var isTargetLinkWithoutHref =
        menuLink.classList.contains("t-menusub__target-link") &&
        (!menuLink.getAttribute("href") ||
          menuLink.getAttribute("href") === "#");
      if (isSubmenuHook || isTargetLinkWithoutHref) {
        menu.addEventListener("menuOverflow", function () {
          t1272_menuBase__checkOverflow(recid, selector);
        });
        return;
      }
      t1272_closeMobileMenu(rec);
    });
  }
  t_menuBase_updateMobileMenuTop(rec);
  window.addEventListener(
    "resize",
    t_throttle(function () {
      if (window.innerWidth > 960) {
        if (menu) menu.style.opacity = "";
        if (menu) menu.style.display = "";
        if (menu) menu.style.height = "";
        if (menu) menu.style.overflowY = "";
        if (menu) {
          var customTopPosition = menu.getAttribute("data-top") || "";
          menu.style.top = customTopPosition;
        }
        mobileMenu.classList.remove(mobileMenuOpenClass);
      }
      t1272_menuBase__checkOverflow(recid, selector);
      t_menuBase_updateMobileMenuTop(rec);
    }, 200),
  );
  document.addEventListener("keydown", function (e) {
    if (e.keyCode !== 27) return;
    if (window.innerWidth > 960) return;
    if (!mobileMenu || !mobileMenu.classList.contains(mobileMenuOpenClass))
      return;
    t1272_closeMobileMenu(rec);
  });
  function t_menuBase_updateMobileMenuTop(rec) {
    var mobileFixedMenu = rec.querySelector(
      ".tmenu-mobile.tmenu-mobile_positionfixed",
    );
    var mobileMenu = rec.querySelector(".tmenu-mobile__menucontent_fixed");
    if (!mobileFixedMenu || !mobileMenu) return;
    if (window.innerWidth <= 960) {
      var computedStyle = window.getComputedStyle(mobileFixedMenu);
      var baseMobileMenuHeight = 64;
      var height = parseFloat(computedStyle.height) || baseMobileMenuHeight;
      var borderBottom = parseFloat(computedStyle.borderBottomWidth) || 0;
      var menuBase = rec.querySelector(".t-menu-base");
      var isSidebar = menuBase.classList.contains(
        "t-menu-base__burgermenu__sidebar",
      );
      var isFullscreen = menuBase.classList.contains(
        "t-menu-base__burgermenu__fullscreen",
      );
      var top = isSidebar || isFullscreen ? 0 : height + borderBottom;
      mobileMenu.style.setProperty("top", top + "px", "important");
    } else {
      mobileMenu.style.setProperty("top", "0px");
    }
  }
}
function t1272_menuBase__checkOverflow(recid, selector) {
  var rec = document.getElementById("rec" + recid);
  var menu = rec ? rec.querySelector(selector) : null;
  if (!menu) return;
  var oldMobileMenuSelector = rec.querySelector(selector + "__mobile");
  var burger = oldMobileMenuSelector
    ? oldMobileMenuSelector
    : rec.querySelector(".tmenu-mobile");
  if (!burger) return;
  var burgerHeight = burger.offsetHeight;
  var windowHeight = document.documentElement.clientHeight;
  var menuPosition =
    menu.style.position || window.getComputedStyle(menu).position;
  var menuHeight = menu.offsetHeight;
  var isFullscreen = menu.classList.contains(
    "t-menu-base__burgermenu__fullscreen",
  );
  if (
    !isFullscreen &&
    menuPosition === "fixed" &&
    menuHeight > windowHeight - burgerHeight
  ) {
    var availableHeight = windowHeight - burgerHeight;
    menu.style.overflow = "auto";
    if (!menu.classList.contains("t-menu-base_sidebar")) {
      menu.style.maxHeight = availableHeight + "px";
    }
  }
}
var t754_POPUP_SHOWED_EVENT_NAME = "catalog:popupShowed";
